var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"그 소문, 알고 계세요?","JPN":"あの噂を知っていますか？","ENG":"Have you heard the rumor?","TWN":"你聽說那個傳聞了嗎？"},"stage":{"bg":"BLACK","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"아카데미에는 벌써 몇 년째 아무도 이름을 모르는 학생이 있대요.","JPN":"アカデミーにはもう何年も前から誰も名前を知らない生徒がいるらしいです。","ENG":"There's a hidden student in the Academy, whose name nobody knows.","TWN":"說是學院裡有個來了好多年，但都沒人知道他的名字的神秘學生。"},"stage":{"bg":"BLACK","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"30번이랑 32번 사이에 있는...... 출석번호 31번.","JPN":"30番と32番の間にいる……出席番号31番。","ENG":"Student Number Thirty-one, between Thirty and Thirty-two.","TWN":"學號應該是30號和32號之間的……31號。"},"stage":{"bg":"CLASS","bgm":"THEMA_STREGA","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"벌써 몇 년씩이나 지났는데도 그 정체를 아는 사람이 없는 번호예요.","JPN":"何年も経っているのに、その正体を誰も知らない番号です。","ENG":"The number has been occupied by someone for years, but no one knows who it is.","TWN":"已經過去好幾年了，還是沒人知道那個學號究竟是什麼人。"},"stage":{"bg":"CLASS","bgm":"THEMA_STREGA","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"사실, 그 사건들만 아니었어도 이런 괴담을 진지하게 믿는 사람은 없었겠지만......","JPN":"あの事件がなかったら、こんな怪談を本気で信じる人はいなかったと思いますが……","ENG":"Actually, no one would be taking it seriously, if it weren't for those strange events.","TWN":"事實上，如果沒有那些事情，應該也不會有人真的相信這種怪談……"},"stage":{"bg":"CLASS","bgm":"THEMA_STREGA","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"문제는 체육대회가 있을 때마다 가끔 1등이나 2등이 비어 있었다는 사실!","JPN":"なんと、運動会が実施されるたびに偶に1位か2位が空いているのです！","ENG":"The problem is, sometimes when the Academy holds a Field Day, for some games, somebody takes first or second place, but nobody knows who!","TWN":"問題是每次運動會比賽時，第一名或第二名都是空的！"},"stage":{"bg":"CLASS","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"아무도 모르는 31번과...... 항상 한 명씩 사라지는 대회 수상자!","JPN":"誰も知らない31番と……いつも1人分足りない入賞者！","ENG":"Student Number Thirty-one, that no one knows about... and the missing Field Day winner.","TWN":"如同謎一般的31號……以及一路過關斬將的大賽優勝者！"},"stage":{"bg":"CLASS","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SORIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"어때요, 브라우니 선생님? 둘 사이에 뭔가 연관이 있는 거 같지 않으세요?","JPN":"どうですか、ブラウニー先生？　この2つの事象に関連性があると思いませんか？","ENG":"What do you say, Ms. Moore? Don't you think there's a connection between them?","TWN":"布朗尼老師，您怎麼看？您不覺得這二者之間有些什麼關係嗎？"},"stage":{"bg":"CLASS","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"호오...... 실종된 적 없는 실종자라. 꽤 흥미로운 현상인걸?","JPN":"ふむふむ……失踪したことのない失踪者かー。なかなか興味深い話ね。","ENG":"Ooh... A missing person who never really went missing? What an interesting subject!","TWN":"呵呵……從未失蹤的失蹤者，好像有點意思。"},"stage":{"bg":"CLASS","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"하지만 선생님이 여러 차례 경고했지?","JPN":"でも、先生が何度も言ったでしょう？","ENG":"But I've warned you several times.","TWN":"不過我應該警告過你很多次吧？"},"stage":{"bg":"CLASS","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"초보자가 함부로 초자연현상을 파헤치려 하는 건 위험해.","JPN":"初心者がむやみに超常現象を探るのは危険です。","ENG":"It's too dangerous for beginners like you to dig into supernatural phenomena.","TWN":"新手擅自調查超自然現象是很危險的事情。"},"stage":{"bg":"CLASS","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"아차하면 되려 당하는 수가 있거든.","JPN":"下手したら危険な目にあってしまうから。","ENG":"You're not prepared for these kinds of situations.","TWN":"稍有不慎就會陷入危險。"},"stage":{"bg":"CLASS","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"하지만 이 소문 때문에 불안하다면서 운동회에 안 나가겠다는 친구들이 많아요.","JPN":"でも、この噂のせいで不安だからと運動会に参加しない子が多いんです。","ENG":"But many of my friends don't want to join the Field Day because of this rumor.","TWN":"不過，有很多學生因為這個傳聞，都不願意參加運動會了。"},"stage":{"bg":"CLASS","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"엄청 열심히 준비했는데...... 이대로는 당일에 운동장이 텅텅 빌지도 몰라요.","JPN":"一生懸命準備したのに……このままじゃ当日グラウンドがガラ空きになってしまいます。","ENG":"We've put a lot into this occasion... What if no one shows up?","TWN":"我們花了那麼多心思準備……這樣下去，可能都沒人參加運動會了。"},"stage":{"bg":"CLASS","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"흐음, 그거라면 걱정 마.","JPN":"なるほど、それなら心配しないで。","ENG":"Hmm, don't worry.","TWN":"呃嗯，那個你不用擔心。"},"stage":{"bg":"CLASS","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"이 <color=#ffd34c>다이브의 정복자</color> 브라우니 선생님에겐 언제나 해결책이 있으니까.","JPN":"この<color=#ffd34c>ダイブの征服者</color>ブラウニー先生は常に解決策を用意してるんだから。","ENG":"I, Brownie Moore, <color=#ffd34c>Dive Conqueror</color>, have a solution. As always.","TWN":"因為我布朗尼<color=#ffd34c>躍入征服者</color>總有解決的辦法啊。"},"stage":{"bg":"CLASS","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"아주 잘 찾아왔어!","JPN":"よく来てくれたね！","ENG":"You've come to the right person!","TWN":"你來得正好！"},"stage":{"bg":"CLASS","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"겁먹은 학생들을 운동회로 불러들이고, 괴담의 진상까지 밝혀낼 수 있는 기가 막힌 방법이 방금 막 떠올랐거든!","JPN":"怯えている生徒たちを運動会に参加させて、\\n怪談の真相も明かせる素晴らしい方法をちょうど今思いついたの！","ENG":"I figured out how to attract the frightened students to the Field Day, as well as uncover the truth!","TWN":"我剛剛想到了一個絕妙的主意，不僅可以讓害怕的學生參加運動會，還能揭開怪談的真相！"},"stage":{"bg":"CLASS","bgm":"THEMA_STREGA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"안녕하십니까, 시청자 여러분!","JPN":"こんにちは、視聴者の皆さん！","ENG":"Good day, everyone!","TWN":"觀眾朋友們，大家好！"},"stage":{"bg":"SS_SPORTS_02","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"저희 중계진은 지금 카운터 아카데미 소유의 블루로즈 군도에 나와 있습니다!","JPN":"私たちは今、カウンターアカデミー所有のブルーローズ群島に来ています！","ENG":"We are currently out on the Blue Rose Islands, owned by the Academy.","TWN":"我們轉播團隊已到達制裁者學院所屬的藍玫瑰群島！"},"stage":{"bg":"SS_SPORTS_02","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"그 중에서도 스타디움 아일랜드라고 불리는 이 쌍둥이 섬에서 오늘 아카데미 학생들의 운동회가 열린다고 합니다!","JPN":"本日、スタジアムアイランドと呼ばれる\\nこの双子の島で、アカデミーの生徒たちの運動会が開かれるそうです！","ENG":"Because today, the Academy is holding a Field Day on these twin islands, known as the Stadium Islands!","TWN":"今天，將在其中名為體育場島的雙子島上舉辨學院運動會！"},"stage":{"bg":"SS_SPORTS_02","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"또한 대회 우승자에겐 그 유명한 <color=#ffd34c>인간 대 다이브</color>의 진행자인 탐험가 브라우니 무어 씨가 직접 이면세계에서 구해 온 아티팩트!","JPN":"また、大会の優勝者にはあの有名は<color=#ffd34c>マンVSダイブ</color>の司会者である\\n探検家ブラウニー・ムーアさんがみずから裏世界で手に入れたアーティファクト！","ENG":"And the winner of the Field Day will win an Artifact that Ms. Brownie Moore, the host of the famous show, <color=#ffd34c>Man vs. Dive</color>, brought back from the Counterside,","TWN":"另外，第一名將獲得知名<color=#ffd34c>人類大躍入</color>的探險家——布朗尼·摩爾女士親自從異界拿回來的人造神器！"},"stage":{"bg":"SS_SPORTS_01","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>소원을 이루어 주는 구슬</color>이 상품으로 주어진다고 하네요!","JPN":"<color=#ffd34c>願いを叶えてくれる玉</color>が景品として与えられるそうです！","ENG":"the <color=#ffd34c>Wishing Ball</color>!","TWN":"<color=#ffd34c>實現願望的許願寶珠</color>！"},"stage":{"bg":"SS_SPORTS_01","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"소원을 이루어 준다니 솔직히 믿기지는 않습니다만 브라우니 무어 씨가 자신의 명성을 걸고 내건 상품이라면 거짓말은 아니겠죠.","JPN":"願いを叶えてくれるなんておとぎ話のようで正直信じがたいですが、\\nブラウニー・ムーアさんがみずからの名誉にかけて準備した物なら嘘ではないでしょう。","ENG":"I don't know if it really grants people's wishes, but if Ms. Moore vouches for it, then it must be good.","TWN":"能夠實現願望的寶珠，這有點神奇到讓人難以置信，不過既然是布朗尼·摩爾女士賭上自己的名譽拿出來的，應該不會是假的吧？"},"stage":{"bg":"SS_SPORTS_01","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L43_1","type":"dialog","speaker":null,"text":{"KOREA":"과연 어떤 소원을 가진 학생이 우승을 거머쥐게 될지 기대가 되는군요.","JPN":"果たしてどんな願いを持った生徒が優勝を勝ち取るのか、楽しみですね。","ENG":"I can't wait to see who's going to win this prize and have their wish come true!","TWN":"這可以實現願望的寶珠最終會花落誰家呢？讓我們拭目以待吧。"},"stage":{"bg":"SS_SPORTS_01","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"최고의 휴양지에서 벌어지는 카운터들의 대결!","JPN":"最高のリゾート地で繰り広げられるカウンターの対決！","ENG":"A contest between Counters at the world's greatest resort!","TWN":"在頂級度假地點所上演的制裁者對決！"},"stage":{"bg":"SS_SPORTS_01","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":null,"text":{"KOREA":"그 장렬하고도 치열한 싸움이...... 잠시 후 시작됩니다!","JPN":"その華麗かつ熾烈な戦いが……まもなく開始します！","ENG":"Their intense and exciting battles will begin shortly!","TWN":"無比激烈的龍虎之鬥……稍後開始！"},"stage":{"bg":"SS_SPORTS_01","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"아카데미 공식 계정으로 한 번 홍보했을 뿐인데......","JPN":"アカデミー公式アカウントで1回伝えただけなのに……","ENG":"We only advertised once through the official Academy account...","TWN":"不過就是用了學院的官方帳號宣傳一下而已……"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"소문이 엄청나게 퍼졌네요. 방송국에서도 촬영을 왔다고요.","JPN":"とてもバズりましたね。テレビ局も取材に来ているみたいです。","ENG":"Yet the news spread so widely that a TV crew has come to film us.","TWN":"就吸引了這麼多人來，連電視臺也來拍攝了。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"아무리 사건해결을 위해서라지만 정말 이렇게 일이 커져도 괜찮을까요?","JPN":"事件解決のためとはいえ、本当にここまで大事になってもいいんですか？","ENG":"You say this is necessary to solve the case, but don't you think we've gone too far?","TWN":"就算是為了破案，把事情鬧得這麼大真的沒關係嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"응? 뭐가?","JPN":"え？　なあに？","ENG":"Hmm? What do you mean?","TWN":"嗯？什麼？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"우승을 하면 무슨 소원이든 이뤄준다니 그런 일이 정말 가능할 리가 없잖아요.","JPN":"優勝すればどんな願いも叶えられるなんて、本当にそんなことができるわけないですよね？","ENG":"The winner gets to have any wish come true? It can't be possible.","TWN":"什麼第一名能夠獲得實現願望的寶珠，也太天方夜譚了吧。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"선생을 못 믿는 제자라니 실망스럽네.","JPN":"先生を信じられない弟子がいるなんて、ガッカリね。","ENG":"I'm so disappointed that my student has no faith in me.","TWN":"居然不相信自己的老師，真讓人失望。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"이 소원구슬은 내가 이면세계의 유적을 한 달이나 파헤쳐가면서 얻은 아티팩트라고!","JPN":"この願い玉は私が裏世界の遺跡を1ヶ月も探し回って、ようやく手に入れたアーティファクトなの！","ENG":"This Wishing Ball is an Artifact that I found in the ruins of the Counterside, after a whole month of digging!","TWN":"這個許願珠是我在異界遺跡裡折騰努力一個多月才找到的人造神器！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"무려 보증서까지 옆에 첨부되어 있었단 말씀!","JPN":"しかも保証書付き！","ENG":"It even had a warranty certificate attached to it!","TWN":"旁邊還附有保證書呢！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"보증서요? 아티팩트는 원래 그런 것도 같이 발굴돼요?","JPN":"保証書ですか？　え、アーティファクトにそんなものが付いているんですか！？","ENG":"A warranty certificate? Do Artifacts usually come with warranties?","TWN":"保證書？人造神器還附帶那種東西嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"으음...... 이건 실은 비밀이긴 한데......","JPN":"えっと……これは内緒なんだけど……","ENG":"Mm... This is supposed to be a secret, but...","TWN":"呃嗯……這個其實是秘密哈……"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"내 라이벌 탐험가인 <color=#ffd34c>인디애나 GAP</color>라는 녀석이 있거든.","JPN":"私のライバル探検家に<color=#ffd34c>インディアナ-甲-</color>って人がいてね。","ENG":"There is an explorer called <color=#ffd34c>Indiana G.A.P.</color>, who is my rival.","TWN":"有個叫<color=#ffd34c>印第安納GAP</color>的探險家，他是我的競爭對手。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"그 녀석은 가끔 자기가 찾은 아티팩트를 가져가는 대신 그 옆에 <color=#ffd34c>GAP 보증서</color>라는 걸 붙여두곤 해.","JPN":"あの人は自分が見つけたアーティファクトを持っていかず、\\n代わりにその横に<color=#ffd34c>-甲-保証書</color>というものを貼っておいたりするの。","ENG":"Sometimes when he finds an Artifact, he doesn't take them, but instead leaves them with what he calls a <color=#ffd34c>G.A.P. Certificate</color>.","TWN":"那傢伙有時候找到自己需要的人造神器後，會在旁邊貼上所謂的<color=#ffd34c>GAP保證書</color>。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"<color=#ffd34c>여기까지 도달한 걸 축하한다, 2등</color>이라는 메시지와 함께 말이야......","JPN":"<color=#ffd34c>ここまでよくたどり着いたな。おめでとう、2位</color>というメッセージを添えてね……","ENG":"Along with the message, \\"<color=#ffd34c>Congratulations on coming in second.</color>\\"","TWN":"還會留下<color=#ffd34c>恭喜你到達這裡，第二名</color>之類的資訊……"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"크으윽! 생각하니 또 분하네! 다음 번엔 반드시 녀석을 제치고 1등이 되고 말거야!","JPN":"くうーっ！　思い出すだけで悔しい！　今度こそあいつを出し抜いて1位になってやるー！","ENG":"Gah! Just the thought of it makes me angry all over again! Next time, I'm going beat him I swear!","TWN":"呃啊啊！想想就生氣！下次我一定要超過那傢伙，成為第一！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"......네, 행운을 빌게요. 선생님.","JPN":"……はい、頑張ってください先生。","ENG":"... Erm. Good luck, Ms. Moore.","TWN":"……嗯，祝您好運，老師。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"그래서 그 보증서 내용은 믿을 만한 거예요?","JPN":"それで、その保証書の内容は信用できるんですか？","ENG":"So, this certificate—is it reliable?","TWN":"那麼，那個保證書的內容可信嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"그거라면 걱정 마. 얄미운 녀석이긴 하지만 아티팩트 감정 실력 하나는 확실하거든.","JPN":"それなら心配しないで。憎らしいやつではあるけど、アーティファクト鑑定の腕だけは確かなの。","ENG":"Don't worry about that. That schmuck is second to none when it comes to Artifact appraisal.","TWN":"那個倒不用擔心。那傢伙雖然討厭，但鑒定人造神器的實力確實不錯。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"한 번은 관리국에서도 분석 불가능하다고 포기한 아티팩트도 감정해 냈다니까.","JPN":"ある時は管理局でも分析不可とお手上げだったアーティファクトを鑑定したからね。","ENG":"One time, he even identified an Artifact that the Administration couldn't.","TWN":"有一次他成功地鑒定了連管理局都說不能分析而放棄的人造神器。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"그 정도라면...... 믿어 볼 만하겠네요.","JPN":"それなら……信じてもよさそうですね。","ENG":"If what you say is true... it should be reliable.","TWN":"那樣的話……應該不會有假。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"덕분에 학생들도 어느 정도 참가의지를 회복했으니 다행이긴 한데......","JPN":"おかげで参加希望の生徒も増えてきたからよかったのですが……","ENG":"Thanks to the tempting prize, many students changed their minds about the Field Day, but...","TWN":"幸好學生們也恢復了一些參與意願，不過……"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"HARIM_REBBIT_NULL_NULL","text":{"KOREA":"정말 이런 방식으로 31번의 정체까지 밝혀낼 수 있을까요?","JPN":"本当にこのやり方で31番の正体を明らかにすることができるんでしょうか？","ENG":"Are you sure we can find Number Thirty-one by doing this?","TWN":"用這種方式真的能查出31號的真實身份嗎？"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"물론이지!","JPN":"もちろん！","ENG":"Of course!","TWN":"當然！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"기록이 맞다면, 31번은 언제나 대회에서 순위권을 노려왔어.","JPN":"記録が正しければ、31番は常に大会でランクインを狙っていた。","ENG":"If the records are correct, Number Thirty-one has always been one of the top players.","TWN":"如果記錄沒錯，31號一直在運動會上名列前茅。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"그리고 지금은 방송국을 포함해서 우승 후보를 쫓는 수십 대의 카메라가 있지.","JPN":"そして今はテレビ局も含め、優勝候補を追いかける数十台のカメラがある。","ENG":"And now, dozens of cameras, including the broadcast ones, are following the front runners.","TWN":"現在包括電視臺在內，有幾十台攝像機都鎖定了奪冠種子選手。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"상대가 투명인간이라고 해도, 이번엔 반드시 눈에 띌 수밖에 없을 거야!","JPN":"相手が透明人間だとしても、今回は必ず見つかるだろうね！","ENG":"There's no way we can miss our target, even if he or she is invisible!","TWN":"就算對方是隱形人，這次也一定會露出行跡！"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARIM_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"하아, 운동회라고 해서 기껏 나와 줬더니......","JPN":"はあ、運動会と聞いたからせっかく出てやったのに……","ENG":"*Sigh* I came here to win.","TWN":"哈啊，我難得來參加個運動會……"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"왜 너 따위 낙오자가 나랑 같은 홍팀에 배정된 거지?","JPN":"なんであんたみたいな落ちこぼれと同じ赤組になるわけ？","ENG":"Why am I on the same team as a loser like you?","TWN":"怎麼會跟你這種失敗者一起分到紅隊呀？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그, 그건 내가 할 소리야!","JPN":"そ、それはこっちのセリフだよ！","ENG":"Th-that's what I'm talking about!","TWN":"那，那句話應該是我要說的吧！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"애초에 난 학생회 간부는 강제 참가라고 해서 끌려나온 거라고!","JPN":"そもそも私は生徒会幹部は強制参加って言われたから参加しただけだし！","ENG":"I'm only here because Student Council members are obliged to participate!","TWN":"我是學生會幹部，所以才會被硬拉來參加運動會！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_HATE"}}}},{"id":"L38_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"운동 신경도 별로라 원래는 구경이나 할 생각이었는데......","JPN":"運動神経もよくないから応援だけしようと思ってたのに……","ENG":"If it wasn't for that, I'd be watching the games from the stands.","TWN":"體育也不是我的強項，本想當個觀眾的……"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_HATE"}}}},{"id":"L39_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"어째서 운동회에서까지 네 뒤치다꺼리에 시달려야 하는 거야?","JPN":"なんで運動会まで来て、あなたの尻拭いをしなきゃいけないの？","ENG":"I can't believe I have to clean up after you, even on Field Day!","TWN":"結果還要在這裡幫你收拾爛攤子？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_HATE"}}}},{"id":"L40_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"흥, 내 수발을 들 수 있다니 너 같은 낙오자에겐 오히려 영광 아냐?","JPN":"は？　尻拭い？　私の付き添いができるなんて、あんたみたいな落ちこぼれにはむしろ光栄じゃない？","ENG":"Hmpf, you should be honored to assist me, loser.","TWN":"哼，你這種失敗者能有機會近身伺候我，是你的榮幸。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_PRIDE"}}}},{"id":"L41_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"그보다 선수로 나온 이상 훈련은 확실히 했겠지?","JPN":"ていうか、選手として参加したんだから事前練習はできてるのよね？","ENG":"Anyway, now that you're here to play, I expect you've practiced, right?","TWN":"不過，既然以選手身份出賽，那應該有認真訓練過吧？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"이유야 뭐가 됐든 내 밑이 들어 온 이상 발목 잡는 짓은 용서 못해!","JPN":"理由はともかく、私の下についたからには足手まといになるのは許さない！","ENG":"It doesn't matter how you got here. As long as you play under me, you'd better not get in my way!","TWN":"不管怎樣，既然來到我的隊伍，就不要扯後腿！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"누가 네 밑으로 들어 왔다는 거야. 하여튼 자기만 안다니까......","JPN":"誰があなたの下についたって？　まったく、とんでもない自己中だわ……","ENG":"Who says I'm under you? Geez, you're so narcissistic!","TWN":"什麼你的隊伍，真是自以為是……"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그런데 나이엘 너, 운동회엔 별 관심 없지 않았어?","JPN":"でもナイエル、あなた運動会には興味なかったんじゃないの？","ENG":"By the way, Naielle. Didn't you say you weren't interested in the Field Day?","TWN":"不過奈爾，你不是對運動會不感興趣嗎？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"인류의 영웅이 되려면 쓸데없는 놀이 할 시간에 시뮬레이션 훈련이나 한 번 더 하는 게 낫다며.","JPN":"人類の英雄になるためには、\\nくだらない遊びに付き合わないでシミュレーション訓練に\\n時間を使った方がいいって言ってなかった？","ENG":"You said, to become humanity's greatest hero, you'd rather do simulation training than play with a ball.","TWN":"你不是說要成為人類的英雄，與其花時間玩沒用的遊戲，還不如再做一次模擬訓練嗎。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"뭐, 나도 처음에는 낙오자들 구경이나 하면서 적당히 놀다 가려고 했지.","JPN":"まあ、私だって最初は落ちこぼれどもを見物しながら、適当に時間をつぶして帰るつもりだったわ。","ENG":"Well, at first, I was just going to look around for a while, watching you losers play.","TWN":"我本來也只是想看看熱鬧，看你們這些失敗者怎麼出洋相的。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"하지만 마침 나한테 딱 필요하던 물건이 우승 상품으로 걸렸더라고.","JPN":"でも、ちょうど私に必要だった物が優勝賞品になったからね。","ENG":"But it turns out that the prize is what I need most right now.","TWN":"不過我發現冠軍獎品正好是我需要的。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"그 소원구슬만 있으면, 나도 한계를 넘어 3종 슬레이어의 경지에 도달할 수 있겠지.","JPN":"その願い玉さえあれば、私も限界を超えて第3種スレイヤーになれるはずよ。","ENG":"With that Wishing Ball, I'll be able to surpass my limits and become a Category 3 Slayer.","TWN":"只要有了那個許願珠，我應該就能突破極限，達到3級屠戮者的境界了。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"아하하핫! 이렇게 된 이상 너 같은 낙오자들에게 내 진정한 실력을 보여 주는 수밖에!","JPN":"アハハハッ！　こうなった以上、あんたたちみたいな落ちこぼれどもに私の本当の実力を見せてやるしかないじゃない！","ENG":"Ah hah hah hah! Watch out, losers. I'll show you what I can really do!","TWN":"啊哈哈哈！既然如此，只能讓你這種失敗者們見識一下我真正的實力了！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"굉장해! 이틀 전까지 운동회엔 아무 관심도 없었던 나이엘이 투지를 불태우고 있어!","JPN":"すごい！　2日前までに運動会に1ミリも興味がなかったナイエルがやる気に満ち溢れてる！","ENG":"Incredible! Naielle, who wasn't interested in the Field Day two days ago, is now burning with determination to win!","TWN":"真不得了！前兩天還對運動會毫無興趣的奈爾正燃燒著熊熊鬥志呢！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"과연! 운동회를 위해 작년부터 연습해 온 선수들을 아무렇지 않게 깔보다니......!","JPN":"さすが！　運動会のために去年から練習してきた選手たちを平然と見下すなんて……！","ENG":"Indeed! And she's casually talking down to players who have been training for this since the last year!","TWN":"哇賽！居然如此無視從去年開始就在為運動會做準備的選手們……！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"저게 바로 강자의 여유라는 건가!","JPN":"あれが正しく強者の余裕ってことか！","ENG":"Is this what you call swag?","TWN":"難道這就是強者的從容嗎！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"(흥, 그야 당연하지. 나처럼 타고난 일류에게 연습 같은 건 필요 없어.)","JPN":"(ふん、当たり前でしょ。私みたいな一流に練習なんか要らないもの。)","ENG":"(Hmpf, of course. I was born elite; I don't have to train to win.)","TWN":"（哼，那是當然。像我這樣天生的強者根本就不需要練習。）"},"stage":{"bg":"BLACK","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"사실 석 달 전부터 온 동네를 뛰어다니면서 하드 트레이닝까지 했다고.","JPN":"実は3ヶ月前から街中を走り回るというハードトレーニングを続けてきたの。","ENG":"Actually, I've been running laps around my neighborhood for three months, training nonstop.","TWN":"其實從三個月前開始，我就在社區裡跑步，還做了高強度訓練。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"(나 같은 엘리트가 남들처럼 똑같이 연습이라도 했다간 경기가 너무 재미없어질 거 아냐.)","JPN":"(私みたいなエリートが他の奴と同じ練習でもしたら、\\nレベルが違いすぎて試合がつまんなくなるでしょ。)","ENG":"(An elite like me shouldn't train as hard as others. No one likes one-sided games.)","TWN":"（像我這樣的精英若是也跟別人一樣練習的話，比賽就太沒意思了不是嗎。）"},"stage":{"bg":"BLACK","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"낙오자 녀석들이 너무 열심히 연습해서 혹시나 질까 봐 다리가 떨리긴 하지만!","JPN":"落ちこぼれたちだって一生懸命練習したはずだし、\\nもし負けたらと思うと怖くて足が震えてきたけど！","ENG":"But I can tell those losers have trained hard as well. I'm worried I might lose to them!","TWN":"失敗者們練習得太認真了，我都害怕自己會輸掉呢！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_SPORTS_NOBG","text":{"KOREA":"아─하하하하하핫!","JPN":"アハハハハハハッ！","ENG":"Mwa hah hah hah!","TWN":"啊─哈哈哈哈哈哈！"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"왠지 나이엘의 생각이랑 말이 바뀌어 나오는 것 같은데?","JPN":"なんだかナイエルの言ってることと考えてることが逆になってるけど。","ENG":"I think Naielle's thoughts and words are switched.","TWN":"我怎麼感覺奈爾在說反話呢？"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"역시 나이엘...... 강하지 않으면 저런 농담을 뻔뻔하게 할 수 있을 리가 없지.","JPN":"さすがナイエル……メンタルがカチカチに強くなければあんな冗談は堂々と言えないだろうな。","ENG":"That's so like Naielle. She's so strong that she can make jokes like that without batting an eye.","TWN":"不愧是奈爾……不夠強的話怎麼可能冠冕堂皇地說出那些話。"},"stage":{"bg":"SPORTSGROUND","bgm":"THEMA_ACADEMY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"흐음...... 바람이 상쾌하네.","JPN":"ふう……爽やかな風だわ。","ENG":"Aah... What a refreshing breeze.","TWN":"哼嗯……風真涼快啊。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"운동회 참가권이 왜 유람선 티켓인가 했는데......","JPN":"運動会の参加券がなんでクルーズチケットなのか不思議に思ったけど……","ENG":"I wondered why the cruise ticket would serve as a Field Day pass.","TWN":"我還想運動會入場券為什麼是遊船票呢……"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"설마 이런 바다 한가운데에 스타디움을 만들어 놓았을 줄이야.","JPN":"まさか、こんな海のど真ん中にスタジアムを作るとはね。","ENG":"Who knew they'd create a stadium in the middle of the sea?","TWN":"誰能想到會在茫茫大海上建了一個體育場呢。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};